import { existsSync, readFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { describe, expect, it } from "vitest";
import { buildSdkPatterns, FRAMEWORK_VARIABLES, FRAMEWORKS, frameworkMockabilityBullets, frameworkReferenceList, withSpanModelFrameworkIds, } from "./frameworks.js";
// repoRoot/bitfab-plugin-lib/src/flows -> repoRoot
const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "../../..");
const docsDir = resolve(repoRoot, "bitfab-docs");
function docsFileFor(docsPath) {
    // "/frameworks/langgraph" -> "<docs>/frameworks/langgraph.mdx"
    return resolve(docsDir, `${docsPath.replace(/^\//, "")}.mdx`);
}
describe("FRAMEWORKS registry", () => {
    it("has unique ids and docs paths", () => {
        const ids = FRAMEWORKS.map((f) => f.id);
        const paths = FRAMEWORKS.map((f) => f.docsPath);
        expect(new Set(ids).size).toBe(ids.length);
        expect(new Set(paths).size).toBe(paths.length);
    });
    it("derives docsPath from id", () => {
        for (const f of FRAMEWORKS) {
            expect(f.docsPath).toBe(`/frameworks/${f.id}`);
        }
    });
    // The flow WebFetches `docs.bitfab.ai{docsPath}` at runtime, so every
    // registry entry MUST have a published docs page. Enforce it locally.
    it.each(FRAMEWORKS.map((f) => [f.id, f]))("%s has a docs page documenting its handler name(s)", (_id, f) => {
        const file = docsFileFor(f.docsPath);
        expect(existsSync(file), `missing docs page: ${file}`).toBe(true);
        const content = readFileSync(file, "utf8");
        expect(content).toContain(f.handler.ts);
        if (f.handler.py) {
            expect(content).toContain(f.handler.py);
        }
    });
    it("is listed on the frameworks overview page", () => {
        const overview = resolve(docsDir, "frameworks/overview.mdx");
        expect(existsSync(overview)).toBe(true);
        const content = readFileSync(overview, "utf8");
        for (const f of FRAMEWORKS) {
            expect(content, `overview omits ${f.id}`).toContain(f.id);
        }
    });
});
describe("derived framework variables", () => {
    it("exposes every framework variable as a non-empty value", () => {
        for (const [name, value] of Object.entries(FRAMEWORK_VARIABLES)) {
            const text = typeof value === "string" ? value : JSON.stringify(value);
            expect(text.length, `empty variable: ${name}`).toBeGreaterThan(0);
        }
    });
    it("sdkPatterns lists keyed handler/wrapper methods but not unkeyed ones", () => {
        const patterns = buildSdkPatterns();
        // callbackHandler frameworks are keyed via their handler and appear with
        // ("key"), in the Python form when present, else the TypeScript form.
        for (const f of FRAMEWORKS.filter((x) => x.handlerKind === "callbackHandler")) {
            expect(patterns).toContain(`${f.handler.py ?? f.handler.ts}("key")`);
        }
        // trace processors with a root wrapper are keyed via that wrapper, so the
        // wrapper appears with ("key") but the bare processor handler does not.
        for (const f of FRAMEWORKS.filter((x) => x.rootWrapper)) {
            expect(patterns).toContain(`${f.rootWrapper.py}("key")`);
            expect(patterns).not.toContain(`${f.handler.py}("key")`);
        }
        // wrappers and bare processors take no key, so their handler is not listed here
        for (const f of FRAMEWORKS.filter((x) => x.handlerKind !== "callbackHandler" && !x.rootWrapper)) {
            expect(patterns).not.toContain(`${f.handler.py}("key")`);
        }
    });
    it("every framework declares autoCapture for at least one span role", () => {
        for (const f of FRAMEWORKS) {
            const roles = Object.values(f.autoCapture);
            expect(roles.length, `${f.id} has empty autoCapture`).toBeGreaterThan(0);
            for (const mechanism of roles) {
                expect(["withSpan", "observed"]).toContain(mechanism);
            }
        }
    });
    it("no framework auto-captures a tool/read/side-effect (child) span as mockable", () => {
        // SDK reality today: every framework's nested tool/retriever/read/side-effect
        // spans come from an observer (callback/processor/stream), never withSpan, so
        // they are not mockable. A future integration that wraps children through
        // withSpan must flip this deliberately (and update the guidance), not silently.
        for (const f of FRAMEWORKS) {
            if (f.autoCapture.child !== undefined) {
                expect(f.autoCapture.child, `${f.id} child capture`).toBe("observed");
            }
        }
    });
    it("mockability lookup reflects each framework's autoCapture verdict", () => {
        const bullets = frameworkMockabilityBullets();
        for (const f of FRAMEWORKS) {
            expect(bullets, `lookup omits ${f.id}`).toContain(f.label);
            const mechanisms = Object.values(f.autoCapture);
            if (mechanisms.includes("observed")) {
                expect(bullets).toContain("NOT mockable");
            }
            if (mechanisms.includes("withSpan")) {
                expect(bullets).toContain("ARE mockable");
            }
        }
        // The two load-bearing SDK facts this whole feature rests on.
        const vercel = FRAMEWORKS.find((f) => f.id === "vercel-ai-sdk");
        expect(vercel?.autoCapture.modelCall).toBe("withSpan");
        const langgraph = FRAMEWORKS.find((f) => f.id === "langgraph");
        expect(langgraph?.autoCapture.child).toBe("observed");
    });
    it("reference list routes every framework to its docs page + methods", () => {
        const list = frameworkReferenceList();
        for (const f of FRAMEWORKS) {
            expect(list).toContain(f.docsPath);
            expect(list).toContain(f.handler.ts);
            if (f.handler.py) {
                expect(list).toContain(f.handler.py);
            }
        }
    });
});
describe("bitfab-web backstop parity", () => {
    // The mockability backstop in bitfab-web (`normalizeAndCorrectTree`) forces
    // every `kind: "auto"` span unmockable EXCEPT frameworks that wrap the model
    // call through `withSpan`. Its exemption set (`WITHSPAN_MODEL_FRAMEWORKS`) is a
    // local literal because the domain layer can't import this registry across
    // packages, so pin it here: a new wrap-based integration added to FRAMEWORKS
    // must be added to that set too, or its model spans get wrongly marked
    // unmockable (the over-marking risk).
    const tracePlanSrc = resolve(repoRoot, "bitfab-web/src/app/lib/domains/tracePlan.ts");
    it("bitfab-web tracePlan.ts is present to pin against", () => {
        expect(existsSync(tracePlanSrc), `missing: ${tracePlanSrc}`).toBe(true);
    });
    it("exempts every wrap-based (withSpan) framework from the auto-span-unmockable backstop", () => {
        const content = readFileSync(tracePlanSrc, "utf8");
        const match = content.match(/WITHSPAN_MODEL_FRAMEWORKS\s*=\s*new Set\(\[([^\]]*)\]\)/);
        expect(match, "WITHSPAN_MODEL_FRAMEWORKS set literal not found in tracePlan.ts").not.toBeNull();
        const backstopIds = new Set(Array.from(match[1].matchAll(/["']([^"']+)["']/g)).map((m) => m[1]));
        const wrapBased = withSpanModelFrameworkIds();
        // Guard against a vacuous pass (e.g. the registry losing its autoCapture data):
        // the Vercel AI SDK is the known wrap-based integration and must be in the list.
        expect(wrapBased).toContain("vercel-ai-sdk");
        for (const id of wrapBased) {
            expect(backstopIds.has(id), `tracePlan.ts WITHSPAN_MODEL_FRAMEWORKS is missing "${id}": this wrap-based framework's model spans would be wrongly marked unmockable`).toBe(true);
        }
    });
});
describe("test-harness coverage", () => {
    // Every first-class framework MUST have a runnable internal harness app in
    // BOTH languages so the setup/assistant harnesses can exercise the plugin
    // against it. Adding a framework to the registry fails here until the
    // matching harness apps exist in test-harness/internal/catalog.json.
    const catalogFile = resolve(repoRoot, "test-harness/internal/catalog.json");
    const catalog = existsSync(catalogFile)
        ? JSON.parse(readFileSync(catalogFile, "utf8"))
        : {};
    it("has a catalog file", () => {
        expect(existsSync(catalogFile), `missing catalog: ${catalogFile}`).toBe(true);
    });
    it.each(FRAMEWORKS.map((f) => [f.id, f]))("%s has harness apps with present entrypoints in every supported language", (_id, f) => {
        // TypeScript is always required; Python only when the framework has a
        // Python integration (a TS-only framework like the Vercel AI SDK has no
        // `handler.py` and so needs no Python harness app).
        const languages = f.handler.py
            ? ["python", "typescript"]
            : ["typescript"];
        for (const language of languages) {
            const match = Object.entries(catalog).find(([, e]) => e.framework === f.id && e.language === language);
            expect(match, `no ${language} harness app for framework "${f.id}" in catalog.json`).toBeDefined();
            if (!match) {
                return;
            }
            const [appId, entry] = match;
            const entrypoint = resolve(repoRoot, "test-harness/internal", appId, entry.entrypoint);
            expect(existsSync(entrypoint), `missing entrypoint for ${appId}: ${entrypoint}`).toBe(true);
        }
    });
});
